const required = ['topic', 'angle', 'key_insight'];
const body = $input.first().json;
const missing = required.filter(k => !body[k]);
if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}
return $input.all();

